Функция ПолучитьСуммарныйДолгПоКонтрагенту(СсылкаНаКонтрагента)

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ
	|	СУММА(Взаиморасчеты.Остаток) КАК Долг
	|ИЗ
	|	РегистрНакопления.Взаиморасчеты КАК Взаиморасчеты
	|ГДЕ
	|	Взаиморасчеты.Договор.Ссылка.Владелец = &Контрагент
	|	И Взаиморасчеты.Остаток > 0";

	Запрос.УстановитьПараметр("Контрагент", СсылкаНаКонтрагента);
	РезультатЗапроса = Запрос.Выполнить();
	ВыборкаДетальныеЗаписи = РезультатЗапроса.Выбрать();

	Если ВыборкаДетальныеЗаписи.Следующий() Тогда
		Возврат ВыборкаДетальныеЗаписи.Долг;
	Иначе
		Возврат 0;
	КонецЕсли; 

КонецФункции // ПолучитьСуммарныйДолгПоКонтрагенту()
